import { useQuery } from '@tanstack/react-query';
import React from 'react'
import { useParams } from 'react-router-dom'
import { Img_URL, fetchSearch } from '../../utils/fetchApi';

const Search = () => {
  const serachTerm = useParams();
  console.log(searchItem);

  const {isLoading,isError,error,data:searchItem}=useQuery({
    queryKey:['searchItem'],
    queryFn: ()=> fetchSearch(`${serachTerm}`)
    .then((res)=>{
      console.log(res);
      return res.results;
    }
      ),
  })


  if (isLoading) {
    return (
      <div className="loading">
        <h1>Loading</h1>
      </div>
    );
  } else if (isError) {
    return (
      <div className="error">
        <p>{error.message}</p>
      </div>
    );
  }else{
  return (
    <section>
      {
        searchItem.map((item)=>(
         <div key={item.title}>
          <img src={`${Img_URL}${item.poster_path}`} alt="?" />
          <p>{item.overview}</p>
        </div>
        ))
      }
    </section>
  )
}
}
export default Search
